    #region Integration Scenarios with Tracing

    [Fact]
    public void TapOnFailure_AfterCombine_TracesCorrectly()
    {
        // Arrange
        using var activityTest = new ActivityTestHelper();

        // Act
        var result = Result.Fail<string>(new Error.InvalidInput(EquatableArray.Create(new FieldViolation(InputPointer.ForProperty("email"), "validation.error") { Detail = "Invalid email" })))
            .Combine(Result.Ok("data"))
            .TapOnFailure(error => { /* Log error */ });

        // Assert
        result.Should().BeFailure();

        // Should have 1 Combine + 1 TapOnFailure activity
        activityTest.AssertActivityCaptured(2);

        // Verify TapOnFailure activity has Error status
        activityTest.AssertActivityCapturedWithStatus("TapOnFailure", ActivityStatusCode.Error);
    }

    [Fact]
    public void TapOnFailure_WithMatch_TracesErrorPath()
    {
        // Arrange
        using var activityTest = new ActivityTestHelper();

        // Act
        var result = Result.Fail<string>(new Error.NotFound(new ResourceRef("Resource", null)) { Detail = "User not found" })
            .Combine(Result.Ok("permissions"))
            .TapOnFailure(error => { /* Log error */ })
            .Match(
                onSuccess: (user, permissions) => "Success",
                onFailure: error => "Error"
            );

        // Assert
        result.Should().Be("Error");

        // Should have Combine + TapOnFailure + Match activities
        activityTest.AssertActivityCaptured(3);
    }

    [Fact]
    public void TapOnFailure_MultipleCombined_TracesAllFailures()
    {
        // Arrange
        using var activityTest = new ActivityTestHelper();

        // Act
        var result = Result.Fail<string>(new Error.InvalidInput(EquatableArray.Create(new FieldViolation(InputPointer.ForProperty("email"), "validation.error") { Detail = "Bad email" })))
            .Combine(Result.Fail<string>(new Error.InvalidInput(EquatableArray.Create(new FieldViolation(InputPointer.ForProperty("phone"), "validation.error") { Detail = "Bad phone" }))))
            .TapOnFailure(error => { /* Log validation errors */ });

        // Assert
        result.Should().BeFailure();

        // Should have Combine + TapOnFailure activities
        activityTest.AssertActivityCapturedWithStatus("Combine", ActivityStatusCode.Error);
        // TapOnFailure should have Error status
        activityTest.AssertActivityCapturedWithStatus("TapOnFailure", ActivityStatusCode.Error);
    }

    [Fact]
    public void TapOnFailure_ChainedWithBind_OnlyTapOnFailureTraces()
    {
        // Arrange
        using var activityTest = new ActivityTestHelper();

        // Act
        var result = Result.Fail<string>(new Error.Unexpected("test") { Detail = "Error" })
            .Combine(Result.Ok("data"))
            .TapOnFailure(error => { /* Log */ })
            .Bind((a, b) => Result.Ok("processed"));

        // Assert
        result.Should().BeFailure();

        // Bind should be short-circuited (no Bind activity)
        // Should only have Combine + TapOnFailure
        activityTest.AssertActivityCapturedWithStatus("TapOnFailure", ActivityStatusCode.Error);
    }

    #endregion

    #region Activity Name Verification

    [Fact]
    public void TapOnFailure_CreatesActivity_WithCorrectName()
    {
        // Arrange
        using var activityTest = new ActivityTestHelper();
        var result = Result.Fail<(int, string)>(new Error.InvalidInput(EquatableArray<FieldViolation>.Empty) { Detail = "Error" });

        // Act
        result.TapOnFailure(() => { });

        // Assert
        var activity = activityTest.AssertActivityCaptured("TapOnFailure");
        activity.DisplayName.Should().Be("TapOnFailure");
    }

    [Fact]
    public void TapOnFailure_WithActionError_CreatesActivity_WithCorrectName()
    {
        // Arrange
        using var activityTest = new ActivityTestHelper();
        var result = Result.Fail<(int, string)>(new Error.NotFound(new ResourceRef("Resource", null)) { Detail = "Not found" });

        // Act
        result.TapOnFailure(error => { });

        // Assert
        var activity = activityTest.AssertActivityCaptured("TapOnFailure");
        activity.DisplayName.Should().Be("TapOnFailure");
    }

    #endregion
}